$('map').imageMapResize();$(function(){$('area').mouseenter(function(){let coords=this.coords.split(',').map(a=>a.trim());$('.captionLocator').css({opacity:'100%',top:coords[1]+'px',left:coords[0]+'px',width:coords[2]-coords[0],height:coords[3]-coords[1]})});$('area').mouseleave(function(){$('.captionLocator').css({opacity:'0%'})})});